  "device_identifier": "cisco-switch",
  "commands": [
    "configure terminal\ninterface Gi0/1\nstorm-control broadcast pps 30\nstorm-control multicast pps 30\nstorm-control unicast pps 30\nend\nwrite memory",
    "show running-config interface Gi0/1",
    "show storm-control interface Gi0/1"
  ]
}

